    34→// Enable to see detailed message communication between window and extension host
    35→const LOG_EXTENSION_HOST_COMMUNICATION = false;
    36→const LOG_USE_COLORS = true;
    37→
    38→type ExtensionHostStartupClassification = {
    39→	owner: 'alexdima';
    40→	comment: 'The startup state of the extension host';
    41→	time: { classification: 'SystemMetaData'; purpose: 'PerformanceAndHealth'; comment: 'The time reported by Date.now().' };
    42→	action: { classification: 'SystemMetaData'; purpose: 'PerformanceAndHealth'; comment: 'The action: starting, success or error.' };
    43→	kind: { classification: 'SystemMetaData'; purpose: 'PerformanceAndHealth'; comment: 'The extension host kind: LocalProcess, LocalWebWorker or Remote.' };
    44→	errorName?: { classification: 'SystemMetaData'; purpose: 'PerformanceAndHealth'; comment: 'The error name.' };
    45→	errorMessage?: { classification: 'SystemMetaData'; purpose: 'PerformanceAndHealth'; comment: 'The error message.' };
    46→	errorStack?: { classification: 'SystemMetaData'; purpose: 'PerformanceAndHealth'; comment: 'The error stack.' };
    47→};
    48→
    49→type ExtensionHostStartupEvent = {
    50→	time: number;
    51→	action: 'starting' | 'success' | 'error';
    52→	kind: string;
    53→	errorName?: string;
    54→	errorMessage?: string;
    55→	errorStack?: string;
    56→};
