    58→export class ExtensionHostManager extends Disposable implements IExtensionHostManager {
    59→
    60→	public readonly onDidExit: Event<[number, string | null]>;
    61→
    62→	private readonly _onDidChangeResponsiveState: Emitter<ResponsiveState> = this._register(new Emitter<ResponsiveState>());
    63→	public readonly onDidChangeResponsiveState: Event<ResponsiveState> = this._onDidChangeResponsiveState.event;
    64→
    65→	/**
    66→	 * A map of already requested activation events to speed things up if the same activation event is triggered multiple times.
    67→	 */
    68→	private readonly _cachedActivationEvents: Map<string, Promise<void>>;
    69→	private readonly _resolvedActivationEvents: Set<string>;
    70→	private _rpcProtocol: RPCProtocol | null;
    71→	private readonly _customers: IDisposable[];
    72→	private readonly _extensionHost: IExtensionHost;
    73→	private _proxy: Promise<IExtensionHostProxy | null> | null;
    74→	private _hasStarted = false;
    75→
    76→	public get pid(): number | null {
    77→		return this._extensionHost.pid;
    78→	}
    79→
    80→	public get kind(): ExtensionHostKind {
    81→		return this._extensionHost.runningLocation.kind;
    82→	}
    83→
    84→	public get startup(): ExtensionHostStartup {
    85→		return this._extensionHost.startup;
    86→	}
    87→
    88→	public get friendyName(): string {
    89→		return friendlyExtHostName(this.kind, this.pid);
    90→	}
    91→
    92→	constructor(
    93→		extensionHost: IExtensionHost,
    94→		initialActivationEvents: string[],
    95→		private readonly _internalExtensionService: IInternalExtensionService,
    96→		@IInstantiationService private readonly _instantiationService: IInstantiationService,
    97→		@IWorkbenchEnvironmentService private readonly _environmentService: IWorkbenchEnvironmentService,
    98→		@ITelemetryService private readonly _telemetryService: ITelemetryService,
    99→		@ILogService private readonly _logService: ILogService,
   100→	) {
   101→		super();
   102→		this._cachedActivationEvents = new Map<string, Promise<void>>();
   103→		this._resolvedActivationEvents = new Set<string>();
   104→		this._rpcProtocol = null;
   105→		this._customers = [];
   106→
   107→		this._extensionHost = extensionHost;
   108→		this.onDidExit = this._extensionHost.onExit;
   109→
   110→		const startingTelemetryEvent: ExtensionHostStartupEvent = {
   111→			time: Date.now(),
   112→			action: 'starting',
   113→			kind: extensionHostKindToString(this.kind)
   114→		};
   115→		this._telemetryService.publicLog2<ExtensionHostStartupEvent, ExtensionHostStartupClassification>('extensionHostStartup', startingTelemetryEvent);
   116→
   117→		this._proxy = this._extensionHost.start().then(
   118→			(protocol) => {
   119→				this._hasStarted = true;
   120→
   121→				// Track healthy extension host startup
   122→				const successTelemetryEvent: ExtensionHostStartupEvent = {
   123→					time: Date.now(),
   124→					action: 'success',
   125→					kind: extensionHostKindToString(this.kind)
   126→				};
   127→				this._telemetryService.publicLog2<ExtensionHostStartupEvent, ExtensionHostStartupClassification>('extensionHostStartup', successTelemetryEvent);
   128→
   129→				return this._createExtensionHostCustomers(this.kind, protocol);
   130→			},
   131→			(err) => {
   132→				this._logService.error(`Error received from starting extension host (kind: ${extensionHostKindToString(this.kind)})`);
   133→				this._logService.error(err);
   134→
   135→				// Track errors during extension host startup
   136→				const failureTelemetryEvent: ExtensionHostStartupEvent = {
   137→					time: Date.now(),
   138→					action: 'error',
   139→					kind: extensionHostKindToString(this.kind)
   140→				};
   141→
   142→				if (err && err.name) {
   143→					failureTelemetryEvent.errorName = err.name;
   144→				}
   145→				if (err && err.message) {
   146→					failureTelemetryEvent.errorMessage = err.message;
   147→				}
   148→				if (err && err.stack) {
   149→					failureTelemetryEvent.errorStack = err.stack;
   150→				}
   151→				this._telemetryService.publicLog2<ExtensionHostStartupEvent, ExtensionHostStartupClassification>('extensionHostStartup', failureTelemetryEvent);
   152→
   153→				return null;
   154→			}
   155→		);
   156→		this._proxy.then(() => {
   157→			initialActivationEvents.forEach((activationEvent) => this.activateByEvent(activationEvent, ActivationKind.Normal));
   158→			this._register(registerLatencyTestProvider({
   159→				measure: () => this.measure()
   160→			}));
   161→		});
   162→	}
   163→
   164→	public async disconnect(): Promise<void> {
   165→		await this._extensionHost?.disconnect?.();
   166→	}
