   168→	public override dispose(): void {
   169→		this._extensionHost?.dispose();
   170→		this._rpcProtocol?.dispose();
   171→
   172→		for (let i = 0, len = this._customers.length; i < len; i++) {
   173→			const customer = this._customers[i];
   174→			try {
   175→				customer.dispose();
   176→			} catch (err) {
   177→				errors.onUnexpectedError(err);
   178→			}
   179→		}
   180→		this._proxy = null;
   181→
   182→		super.dispose();
   183→	}
   184→
   185→	private async measure(): Promise<ExtHostLatencyResult | null> {
   186→		const proxy = await this._proxy;
   187→		if (!proxy) {
   188→			return null;
   189→		}
   190→		const latency = await this._measureLatency(proxy);
   191→		const down = await this._measureDown(proxy);
   192→		const up = await this._measureUp(proxy);
   193→		return {
   194→			remoteAuthority: this._extensionHost.remoteAuthority,
   195→			latency,
   196→			down,
   197→			up
   198→		};
   199→	}
   200→
   201→	public async ready(): Promise<void> {
   202→		await this._proxy;
   203→	}
   204→
   205→	private async _measureLatency(proxy: IExtensionHostProxy): Promise<number> {
   206→		const COUNT = 10;
   207→
   208→		let sum = 0;
   209→		for (let i = 0; i < COUNT; i++) {
   210→			const sw = StopWatch.create();
   211→			await proxy.test_latency(i);
   212→			sw.stop();
   213→			sum += sw.elapsed();
   214→		}
   215→		return (sum / COUNT);
   216→	}
   217→
   218→	private static _convert(byteCount: number, elapsedMillis: number): number {
   219→		return (byteCount * 1000 * 8) / elapsedMillis;
   220→	}
   221→
   222→	private async _measureUp(proxy: IExtensionHostProxy): Promise<number> {
   223→		const SIZE = 10 * 1024 * 1024; // 10MB
   224→
   225→		const buff = VSBuffer.alloc(SIZE);
   226→		const value = Math.ceil(Math.random() * 256);
   227→		for (let i = 0; i < buff.byteLength; i++) {
   228→			buff.writeUInt8(i, value);
   229→		}
   230→		const sw = StopWatch.create();
   231→		await proxy.test_up(buff);
   232→		sw.stop();
   233→		return ExtensionHostManager._convert(SIZE, sw.elapsed());
   234→	}
   235→
   236→	private async _measureDown(proxy: IExtensionHostProxy): Promise<number> {
   237→		const SIZE = 10 * 1024 * 1024; // 10MB
   238→
   239→		const sw = StopWatch.create();
   240→		await proxy.test_down(SIZE);
   241→		sw.stop();
   242→		return ExtensionHostManager._convert(SIZE, sw.elapsed());
   243→	}
   244→
   245→	private _createExtensionHostCustomers(kind: ExtensionHostKind, protocol: IMessagePassingProtocol): IExtensionHostProxy {
   246→
   247→		let logger: IRPCProtocolLogger | null = null;
   248→		if (LOG_EXTENSION_HOST_COMMUNICATION || this._environmentService.logExtensionHostCommunication) {
   249→			logger = new RPCLogger(kind);
   250→		} else if (TelemetryRPCLogger.isEnabled()) {
   251→			logger = new TelemetryRPCLogger(this._telemetryService);
   252→		}
   253→
   254→		this._rpcProtocol = new RPCProtocol(protocol, logger);
   255→		this._register(this._rpcProtocol.onDidChangeResponsiveState((responsiveState: ResponsiveState) => this._onDidChangeResponsiveState.fire(responsiveState)));
   256→		let extensionHostProxy: IExtensionHostProxy | null = null as IExtensionHostProxy | null;
   257→		let mainProxyIdentifiers: ProxyIdentifier<any>[] = [];
   258→		const extHostContext: IInternalExtHostContext = {
   259→			remoteAuthority: this._extensionHost.remoteAuthority,
   260→			extensionHostKind: this.kind,
   261→			getProxy: <T>(identifier: ProxyIdentifier<T>): Proxied<T> => this._rpcProtocol!.getProxy(identifier),
   262→			set: <T, R extends T>(identifier: ProxyIdentifier<T>, instance: R): R => this._rpcProtocol!.set(identifier, instance),
   263→			dispose: (): void => this._rpcProtocol!.dispose(),
   264→			assertRegistered: (identifiers: ProxyIdentifier<any>[]): void => this._rpcProtocol!.assertRegistered(identifiers),
   265→			drain: (): Promise<void> => this._rpcProtocol!.drain(),
   266→
   267→			//#region internal
   268→			internalExtensionService: this._internalExtensionService,
   269→			_setExtensionHostProxy: (value: IExtensionHostProxy): void => {
   270→				extensionHostProxy = value;
   271→			},
   272→			_setAllMainProxyIdentifiers: (value: ProxyIdentifier<any>[]): void => {
   273→				mainProxyIdentifiers = value;
   274→			},
   275→			//#endregion
   276→		};
   277→
   278→		// Named customers
   279→		const namedCustomers = ExtHostCustomersRegistry.getNamedCustomers();
   280→		for (let i = 0, len = namedCustomers.length; i < len; i++) {
   281→			const [id, ctor] = namedCustomers[i];
   282→			try {
   283→				const instance = this._instantiationService.createInstance(ctor, extHostContext);
   284→				this._customers.push(instance);
   285→				this._rpcProtocol.set(id, instance);
   286→			} catch (err) {
   287→				this._logService.error(`Cannot instantiate named customer: '${id.sid}'`);
   288→				this._logService.error(err);
   289→				errors.onUnexpectedError(err);
   290→			}
   291→		}
   292→
   293→		// Customers
   294→		const customers = ExtHostCustomersRegistry.getCustomers();
   295→		for (const ctor of customers) {
   296→			try {
   297→				const instance = this._instantiationService.createInstance(ctor, extHostContext);
   298→				this._customers.push(instance);
   299→			} catch (err) {
   300→				this._logService.error(err);
   301→				errors.onUnexpectedError(err);
   302→			}
   303→		}
   304→
   305→		if (!extensionHostProxy) {
   306→			throw new Error(`Missing IExtensionHostProxy!`);
   307→		}
   308→
   309→		// Check that no named customers are missing
   310→		this._rpcProtocol.assertRegistered(mainProxyIdentifiers);
   311→
   312→		return extensionHostProxy;
   313→	}
   314→
   315→	public async activate(extension: ExtensionIdentifier, reason: ExtensionActivationReason): Promise<boolean> {
   316→		const proxy = await this._proxy;
   317→		if (!proxy) {
   318→			return false;
   319→		}
   320→		return proxy.activate(extension, reason);
   321→	}
   322→
   323→	public activateByEvent(activationEvent: string, activationKind: ActivationKind): Promise<void> {
   324→		if (activationKind === ActivationKind.Immediate && !this._hasStarted) {
   325→			return Promise.resolve();
   326→		}
   327→
   328→		if (!this._cachedActivationEvents.has(activationEvent)) {
   329→			this._cachedActivationEvents.set(activationEvent, this._activateByEvent(activationEvent, activationKind));
   330→		}
   331→		return this._cachedActivationEvents.get(activationEvent)!;
   332→	}
   333→
   334→	public activationEventIsDone(activationEvent: string): boolean {
   335→		return this._resolvedActivationEvents.has(activationEvent);
   336→	}
   337→
   338→	private async _activateByEvent(activationEvent: string, activationKind: ActivationKind): Promise<void> {
   339→		if (!this._proxy) {
   340→			return;
   341→		}
   342→		const proxy = await this._proxy;
   343→		if (!proxy) {
   344→			// this case is already covered above and logged.
   345→			// i.e. the extension host could not be started
   346→			return;
   347→		}
   348→
   349→		if (!this._extensionHost.extensions!.containsActivationEvent(activationEvent)) {
   350→			this._resolvedActivationEvents.add(activationEvent);
   351→			return;
   352→		}
   353→
   354→		await proxy.activateByEvent(activationEvent, activationKind);
   355→		this._resolvedActivationEvents.add(activationEvent);
   356→	}
   357→
   358→	public async getInspectPort(tryEnableInspector: boolean): Promise<{ port: number; host: string } | undefined> {
   359→		if (this._extensionHost) {
   360→			if (tryEnableInspector) {
   361→				await this._extensionHost.enableInspectPort();
   362→			}
   363→			const port = this._extensionHost.getInspectPort();
   364→			if (port) {
   365→				return port;
   366→			}
   367→		}
   368→
   369→		return undefined;
   370→	}
