   446→	public async deltaExtensions(incomingExtensionsDelta: IExtensionDescriptionDelta): Promise<void> {
   447→		const proxy = await this._proxy;
   448→		if (!proxy) {
   449→			return;
   450→		}
   451→		const outgoingExtensionsDelta = this._extensionHost.extensions!.delta(incomingExtensionsDelta);
   452→		if (!outgoingExtensionsDelta) {
   453→			// The extension host already has this version of the extensions.
   454→			return;
   455→		}
   456→		return proxy.deltaExtensions(outgoingExtensionsDelta);
   457→	}
