   372→	public async resolveAuthority(remoteAuthority: string, resolveAttempt: number): Promise<IResolveAuthorityResult> {
   373→		const sw = StopWatch.create(false);
   374→		const prefix = () => `[${extensionHostKindToString(this._extensionHost.runningLocation.kind)}${this._extensionHost.runningLocation.affinity}][resolveAuthority(${getRemoteAuthorityPrefix(remoteAuthority)},${resolveAttempt})][${sw.elapsed()}ms] `;
   375→		const logInfo = (msg: string) => this._logService.info(`${prefix()}${msg}`);
   376→		const logError = (msg: string, err: any = undefined) => this._logService.error(`${prefix()}${msg}`, err);
   377→
   378→		logInfo(`obtaining proxy...`);
   379→		const proxy = await this._proxy;
   380→		if (!proxy) {
   381→			logError(`no proxy`);
   382→			return {
   383→				type: 'error',
   384→				error: {
   385→					message: `Cannot resolve authority`,
   386→					code: RemoteAuthorityResolverErrorCode.Unknown,
   387→					detail: undefined
   388→				}
   389→			};
   390→		}
   391→		logInfo(`invoking...`);
   392→		const intervalLogger = new IntervalTimer();
   393→		try {
   394→			intervalLogger.cancelAndSet(() => logInfo('waiting...'), 1000);
   395→			const resolverResult = await proxy.resolveAuthority(remoteAuthority, resolveAttempt);
   396→			intervalLogger.dispose();
   397→			if (resolverResult.type === 'ok') {
   398→				logInfo(`returned ${resolverResult.value.authority.connectTo}`);
   399→			} else {
   400→				logError(`returned an error`, resolverResult.error);
   401→			}
   402→			return resolverResult;
   403→		} catch (err) {
   404→			intervalLogger.dispose();
   405→			logError(`returned an error`, err);
   406→			return {
   407→				type: 'error',
   408→				error: {
   409→					message: err.message,
   410→					code: RemoteAuthorityResolverErrorCode.Unknown,
   411→					detail: err
   412→				}
   413→			};
   414→		}
   415→	}
   416→
   417→	public async getCanonicalURI(remoteAuthority: string, uri: URI): Promise<URI | null> {
   418→		const proxy = await this._proxy;
   419→		if (!proxy) {
   420→			throw new Error(`Cannot resolve canonical URI`);
   421→		}
   422→		return proxy.getCanonicalURI(remoteAuthority, uri);
