   473→export function friendlyExtHostName(kind: ExtensionHostKind, pid: number | null) {
   474→	if (pid) {
   475→		return `${extensionHostKindToString(kind)} pid: ${pid}`;
   476→	}
   477→	return `${extensionHostKindToString(kind)}`;
   478→}
   479→
   480→const colorTables = [
   481→	['#2977B1', '#FC802D', '#34A13A', '#D3282F', '#9366BA'],
   482→	['#8B564C', '#E177C0', '#7F7F7F', '#BBBE3D', '#2EBECD']
   483→];
   484→
   485→function prettyWithoutArrays(data: any): any {
   486→	if (Array.isArray(data)) {
   487→		return data;
   488→	}
   489→	if (data && typeof data === 'object' && typeof data.toString === 'function') {
   490→		const result = data.toString();
   491→		if (result !== '[object Object]') {
   492→			return result;
   493→		}
   494→	}
   495→	return data;
   496→}
   497→
   498→function pretty(data: any): any {
   499→	if (Array.isArray(data)) {
   500→		return data.map(prettyWithoutArrays);
   501→	}
   502→	return prettyWithoutArrays(data);
   503→}
   504→
   505→class RPCLogger implements IRPCProtocolLogger {
   506→
   507→	private _totalIncoming = 0;
   508→	private _totalOutgoing = 0;
   509→
   510→	constructor(
   511→		private readonly _kind: ExtensionHostKind
   512→	) { }
   513→
   514→	private _log(direction: string, totalLength: number, msgLength: number, req: number, initiator: RequestInitiator, str: string, data: any): void {
   515→		data = pretty(data);
   516→
   517→		const colorTable = colorTables[initiator];
   518→		const color = LOG_USE_COLORS ? colorTable[req % colorTable.length] : '#000000';
   519→		let args = [`%c[${extensionHostKindToString(this._kind)}][${direction}]%c[${String(totalLength).padStart(7)}]%c[len: ${String(msgLength).padStart(5)}]%c${String(req).padStart(5)} - ${str}`, 'color: darkgreen', 'color: grey', 'color: grey', `color: ${color}`];
   520→		if (/\($/.test(str)) {
   521→			args = args.concat(data);
   522→			args.push(')');
   523→		} else {
   524→			args.push(data);
   525→		}
   526→		console.log.apply(console, args as [string, ...string[]]);
   527→	}
   528→
   529→	logIncoming(msgLength: number, req: number, initiator: RequestInitiator, str: string, data?: any): void {
   530→		this._totalIncoming += msgLength;
   531→		this._log('Ext \u2192 Win', this._totalIncoming, msgLength, req, initiator, str, data);
   532→	}
   533→
   534→	logOutgoing(msgLength: number, req: number, initiator: RequestInitiator, str: string, data?: any): void {
   535→		this._totalOutgoing += msgLength;
   536→		this._log('Win \u2192 Ext', this._totalOutgoing, msgLength, req, initiator, str, data);
   537→	}
   538→}
   539→
   540→interface RPCTelemetryData {
   541→	type: string;
   542→	length: number;
   543→}
   544→
   545→type RPCTelemetryDataClassification = {
   546→	owner: 'jrieken';
   547→	comment: 'Insights about RPC message sizes';
   548→	type: { classification: 'SystemMetaData'; purpose: 'PerformanceAndHealth'; comment: 'The type of the RPC message' };
   549→	length: { classification: 'SystemMetaData'; purpose: 'PerformanceAndHealth'; comment: 'The byte-length of the RPC message' };
   550→};
   551→
   552→class TelemetryRPCLogger implements IRPCProtocolLogger {
   553→
   554→	static isEnabled(): boolean {
   555→		return Math.random() < 0.0001; // 0.01% of users
   556→	}
   557→
   558→	private readonly _pendingRequests = new Map<number, string>();
   559→
   560→	constructor(@ITelemetryService private readonly _telemetryService: ITelemetryService) { }
   561→
   562→	logIncoming(msgLength: number, req: number, initiator: RequestInitiator, str: string): void {
   563→
   564→		if (initiator === RequestInitiator.LocalSide && /^receiveReply(Err)?:/.test(str)) {
   565→			// log the size of reply messages
   566→			const requestStr = this._pendingRequests.get(req) ?? 'unknown_reply';
   567→			this._pendingRequests.delete(req);
   568→			this._telemetryService.publicLog2<RPCTelemetryData, RPCTelemetryDataClassification>('extensionhost.incoming', {
   569→				type: `${str} ${requestStr}`,
   570→				length: msgLength
   571→			});
   572→		}
   573→
   574→		if (initiator === RequestInitiator.OtherSide && /^receiveRequest /.test(str)) {
   575→			// incoming request
   576→			this._telemetryService.publicLog2<RPCTelemetryData, RPCTelemetryDataClassification>('extensionhost.incoming', {
   577→				type: `${str}`,
   578→				length: msgLength
   579→			});
   580→		}
   581→	}
   582→
   583→	logOutgoing(msgLength: number, req: number, initiator: RequestInitiator, str: string): void {
   584→
   585→		if (initiator === RequestInitiator.LocalSide && str.startsWith('request: ')) {
   586→			this._pendingRequests.set(req, str);
   587→			this._telemetryService.publicLog2<RPCTelemetryData, RPCTelemetryDataClassification>('extensionhost.outgoing', {
   588→				type: str,
   589→				length: msgLength
   590→			});
   591→		}
   592→	}
   593→}
   594→
   595→interface ExtHostLatencyResult {
   596→	remoteAuthority: string | null;
   597→	up: number;
   598→	down: number;
   599→	latency: number;
   600→}
   601→
   602→interface ExtHostLatencyProvider {
   603→	measure(): Promise<ExtHostLatencyResult | null>;
   604→}
   605→
   606→const providers: ExtHostLatencyProvider[] = [];
   607→function registerLatencyTestProvider(provider: ExtHostLatencyProvider): IDisposable {
   608→	providers.push(provider);
   609→	return {
   610→		dispose: () => {
   611→			for (let i = 0; i < providers.length; i++) {
   612→				if (providers[i] === provider) {
   613→					providers.splice(i, 1);
   614→					return;
   615→				}
   616→			}
   617→		}
   618→	};
   619→}
   620→
   621→function getLatencyTestProviders(): ExtHostLatencyProvider[] {
   622→	return providers.slice(0);
   623→}
   624→
   625→registerAction2(class MeasureExtHostLatencyAction extends Action2 {
   626→
   627→	constructor() {
   628→		super({
   629→			id: 'editor.action.measureExtHostLatency',
   630→			title: nls.localize2('measureExtHostLatency', "Measure Extension Host Latency"),
   631→			category: Categories.Developer,
   632→			f1: true
   633→		});
   634→	}
   635→
   636→	async run(accessor: ServicesAccessor) {
   637→
   638→		const editorService = accessor.get(IEditorService);
   639→
   640→		const measurements = await Promise.all(getLatencyTestProviders().map(provider => provider.measure()));
   641→		editorService.openEditor({ resource: undefined, contents: measurements.map(MeasureExtHostLatencyAction._print).join('\n\n'), options: { pinned: true } });
   642→	}
   643→
   644→	private static _print(m: ExtHostLatencyResult | null): string {
   645→		if (!m) {
   646→			return '';
   647→		}
   648→		return `${m.remoteAuthority ? `Authority: ${m.remoteAuthority}\n` : ``}Roundtrip latency: ${m.latency.toFixed(3)}ms\nUp: ${MeasureExtHostLatencyAction._printSpeed(m.up)}\nDown: ${MeasureExtHostLatencyAction._printSpeed(m.down)}\n`;
   649→	}
   650→
   651→	private static _printSpeed(n: number): string {
   652→		if (n <= 1024) {
   653→			return `${n} bps`;
   654→		}
   655→		if (n < 1024 * 1024) {
   656→			return `${(n / 1024).toFixed(1)} kbps`;
   657→		}
   658→		return `${(n / 1024 / 1024).toFixed(1)} Mbps`;
   659→	}
   660→});
