   372→	public async resolveAuthority(remoteAuthority: string, resolveAttempt: number): Promise<IResolveAuthorityResult> {
   373→		const sw = StopWatch.create(false);
   374→		const prefix = () => `[${extensionHostKindToString(this._extensionHost.runningLocation.kind)}${this._extensionHost.runningLocation.affinity}][resolveAuthority(${getRemoteAuthorityPrefix(remoteAuthority)},${resolveAttempt})][${sw.elapsed()}ms] `;
   375→		const logInfo = (msg: string) => this._logService.info(`${prefix()}${msg}`);
   376→		const logError = (msg: string, err: any = undefined) => this._logService.error(`${prefix()}${msg}`, err);
   377→
   378→		logInfo(`obtaining proxy...`);
   379→		const proxy = await this._proxy;
   380→		if (!proxy) {
   381→			logError(`no proxy`);
   382→			return {
   383→				type: 'error',
   384→				error: {
   385→					message: `Cannot resolve authority`,
   386→					code: RemoteAuthorityResolverErrorCode.Unknown,
   387→					detail: undefined
   388→				}
   389→			};
