   403→		} catch (err) {
   404→			intervalLogger.dispose();
   405→			logError(`returned an error`, err);
   406→			return {
   407→				type: 'error',
   408→				error: {
   409→					message: err.message,
   410→					code: RemoteAuthorityResolverErrorCode.Unknown,
   411→					detail: err
   412→				}
   413→			};
   414→		}
   415→	}
