    67→	constructor(
    68→		@IInstantiationService instantiationService: IInstantiationService,
    69→		@INotificationService notificationService: INotificationService,
    70→		@IWorkbenchEnvironmentService environmentService: IWorkbenchEnvironmentService,
    71→		@ITelemetryService telemetryService: ITelemetryService,
    72→		@IWorkbenchExtensionEnablementService extensionEnablementService: IWorkbenchExtensionEnablementService,
    73→		@IFileService fileService: IFileService,
    74→		@IProductService productService: IProductService,
    75→		@IWorkbenchExtensionManagementService extensionManagementService: IWorkbenchExtensionManagementService,
    76→		@IWorkspaceContextService contextService: IWorkspaceContextService,
    77→		@IConfigurationService configurationService: IConfigurationService,
    78→		@IExtensionManifestPropertiesService extensionManifestPropertiesService: IExtensionManifestPropertiesService,
    79→		@ILogService logService: ILogService,
    80→		@IRemoteAgentService remoteAgentService: IRemoteAgentService,
    81→		@IRemoteExtensionsScannerService remoteExtensionsScannerService: IRemoteExtensionsScannerService,
