    86→		@IRemoteExplorerService private readonly _remoteExplorerService: IRemoteExplorerService,
    87→		@IExtensionGalleryService private readonly _extensionGalleryService: IExtensionGalleryService,
    88→		@IWorkspaceTrustManagementService private readonly _workspaceTrustManagementService: IWorkspaceTrustManagementService,
    89→		@IDialogService dialogService: IDialogService,
    90→	) {
    91→		const extensionsProposedApi = instantiationService.createInstance(ExtensionsProposedApi);
    92→		const extensionScanner = instantiationService.createInstance(CachedExtensionScanner);
    93→		const extensionHostFactory = new NativeExtensionHostFactory(
    94→			extensionsProposedApi,
    95→			extensionScanner,
    96→			() => this._getExtensionRegistrySnapshotWhenReady(),
    97→			instantiationService,
    98→			environmentService,
    99→			extensionEnablementService,
   100→			configurationService,
   101→			remoteAgentService,
   102→			remoteAuthorityResolverService,
   103→			logService
   104→		);
