   106→			{ hasLocalProcess: true, allowRemoteExtensionsInLocalWebWorker: false },
   107→			extensionsProposedApi,
   108→			extensionHostFactory,
   109→			new NativeExtensionHostKindPicker(environmentService, configurationService, logService),
