   120→			extensionManifestPropertiesService,
   121→			logService,
   122→			remoteAgentService,
   123→			remoteExtensionsScannerService,
   124→			lifecycleService,
   125→			remoteAuthorityResolverService,
   126→			dialogService
   127→		);
   128→
   129→		this._extensionScanner = extensionScanner;
