   139→			runWhenWindowIdle(mainWindow, () => {
   140→				this._initialize();
   141→			}, 50 /*max delay*/);
   142→		});
   143→	}
   144→
   145→	private async _scanAllLocalExtensions(): Promise<IExtensionDescription[]> {
   146→		return this._extensionScanner.scannedExtensions;
   147→	}
   148→
   149→	protected override _onExtensionHostCrashed(extensionHost: IExtensionHostManager, code: number, signal: string | null): void {
   150→
   151→		const activatedExtensions: ExtensionIdentifier[] = [];
   152→		const extensionsStatus = this.getExtensionsStatus();
   153→		for (const key of Object.keys(extensionsStatus)) {
   154→			const extensionStatus = extensionsStatus[key];
   155→			if (extensionStatus.activationStarted && extensionHost.containsExtension(extensionStatus.id)) {
   156→				activatedExtensions.push(extensionStatus.id);
   157→			}
   158→		}
   159→
   160→		super._onExtensionHostCrashed(extensionHost, code, signal);
   161→
   162→		if (extensionHost.kind === ExtensionHostKind.LocalProcess) {
   163→			if (code === ExtensionHostExitCode.VersionMismatch) {
   164→				this._notificationService.prompt(
   165→					Severity.Error,
   166→					nls.localize('extensionService.versionMismatchCrash', "Extension host cannot start: version mismatch."),
   167→					[{
   168→						label: nls.localize('relaunch', "Relaunch VS Code"),
   169→						run: () => {
   170→							this._instantiationService.invokeFunction((accessor) => {
   171→								const hostService = accessor.get(IHostService);
   172→								hostService.restart();
   173→							});
   174→						}
   175→					}]
   176→				);
   177→				return;
   178→			}
   179→
