   186→				this._logService.info(`Automatically restarting the extension host.`);
   187→				this._notificationService.status(nls.localize('extensionService.autoRestart', "The extension host terminated unexpectedly. Restarting..."), { hideAfter: 5000 });
   188→				this.startExtensionHosts();
   189→			} else {
   190→				const choices: IPromptChoice[] = [];
   191→				if (this._environmentService.isBuilt) {
   192→					choices.push({
   193→						label: nls.localize('startBisect', "Start Extension Bisect"),
   194→						run: () => {
   195→							this._instantiationService.invokeFunction(accessor => {
   196→								const commandService = accessor.get(ICommandService);
   197→								commandService.executeCommand('extension.bisect.start');
   198→							});
   199→						}
   200→					});

