			break;
		}
		case MessageType.ReplyOKJSON: {
			let value = MessageIO.deserializeReplyOKJSON(buff);
			if (this._uriTransformer) {
				value = transformIncomingURIs(value, this._uriTransformer);
			}
			this._receiveReply(msgLength, req, value);

